// ┌─────────────────────────────────────────────┐
// │  Edit the values below, then click Test workflow │
// └─────────────────────────────────────────────┘
const config = {
  brandName:  'Acme Analytics',          // your brand, as it appears in titles/URLs
  wpUrl:      'https://acme.com',         // your site (used to detect YOUR ranking)
  competitors: ['competitor1.com', 'competitor2.com']  // who you're racing
};
return [{ json: config }];

// Parse SERP: rank, features, PAA, competitors
const json = $input.first().json;
const organic = (json.organic_results || []).map((r, i) => ({
  position: r.position || i + 1,
  title: r.title,
  url: r.link,
  domain: r.link ? r.link.split('/')[2] : '',
  snippet: r.snippet,
  isUs: (r.link || '').includes($json.brandName?.toLowerCase().replace(/[^a-z]/g, '') || 'XXX') || False
}));

const ourPosition = organic.find(r => r.isUs)?.position || 0;

// Detect SERP features
const features = [];
if (json.answer_box) features.push('answer_box');
if (json.knowledge_graph) features.push('knowledge_graph');
if (json.featured_snippet) features.push('featured_snippet');
if (json.people_also_ask) features.push('paa');
if (json.video_results) features.push('video');
if (json.image_results) features.push('images');
if (json.news_results) features.push('news');
if (json.shopping_results) features.push('shopping');
if (json.local_pack) features.push('local_pack');

// Extract PAA questions
const paaQuestions = (json.people_also_ask || []).slice(0, 8).map(p => p.question).filter(Boolean);

// Featured snippet owner
const snippetOwner = json.featured_snippet?.links?.[0]?.url || json.answer_box?.links?.[0]?.url || null;

return [{
  json: {
    ...json,
    keyword: json.search_parameters?.q || $json.keyword,
    ourPosition,
    totalResults: json.search_information?.total_results,
    features,
    paaQuestions,
    snippetOwner,
    organicResults: organic.slice(0, 10),
    checkedAt: new Date().toISOString()
  }
}];

