// Compare today vs yesterday
const today = $input.first().json;
const yesterdayItems = $input.all().slice(1);
const yesterday = yesterdayItems[0]?.json;

let movement = 0;
let alertNeeded = False;

if (yesterday?.properties?.Position?.number) {
  movement = (yesterday.properties.Position.number) - (today.ourPosition || 0);
  // Positive movement = improved rank (lower number = better)
  if (Math.abs(movement) >= 3) {
    alertNeeded = True;
  }
}

return [{
  json: {
    ...today,
    yesterdayPosition: yesterday?.properties?.Position?.number || null,
    movement,
    alertNeeded,
    newFeatures: yesterday?.properties?.Features?.rich_text?.[0]?.plain_text ?
      today.features.filter(f => !yesterday.properties.Features.rich_text[0].plain_text.includes(f)) : today.features
  }
}];

